VALUES
  ('optometrist-moex-01244', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關角膜塑型隱形眼鏡逆幾何設計（reversegeometry）鏡片，下列敘述何者正確？', '["逆轉弧區（reversecurve）較中央光學區基弧（opticalzoneradius）為陡", "逆轉弧區較中央光學區基弧為平", "中央光學區基弧較定位區弧度（alignmentcurve）為陡", "逆轉弧區較定位區弧度為平"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01245', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '利用角膜塑型片減緩近視度數增加的機轉雖未完全清楚，但目前較為接受的假說為塑型片於視網膜上形成 一個：', '["遠視周邊離焦", "近視周邊離焦", "遠視中心離焦", "近視中心離焦"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01246', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '下列配戴隱形眼鏡所引起的併發症何者與綠膿桿菌內毒素最為相關？', '["周邊角膜潰瘍（contactlensperipheralulcer）", "急性紅眼反應（contactlens-inducedacuteredeye,CLARE）", "角膜磨損和糜爛（cornealabrasionsanderosions）", "上部角膜上皮弓形缺損（superiorepithelialarcuatelesions,SEALs）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01247', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '關於硬式散光隱形眼鏡鏡片—圓錐角膜之驗配，下列何者錯誤？', '["大多數圓錐角膜設計是基弧比典型的BOZR更陡，並結合一系列具有逐漸變平的邊弧，以吻合相對正常 的外圍角膜", "術語「表觀觸碰（apparenttouch）」旨在反映鏡片和角膜頂端之間有相當大的物理觸碰", "三點觸碰（three-point touch）是指在角膜頂端「表觀觸碰」，且大部分周圍的角膜上有周邊接觸形 （peripheralbearing）", "術語「表觀觸碰」旨在反映鏡片和角膜頂端之間缺乏真正的物理觸碰"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01248', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有一物在距離此透鏡的20cm處，透鏡為+8.00D，此透鏡位於物體右側，則此物透過鏡片最終聚焦形成的 物像，成像位置位於何處？', '["鏡片左側40cm處", "鏡片右側25cm處", "鏡片左側12.5cm處", "鏡片右側33cm處"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01249', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '一檢測者使用旋轉鏡片測量器測得冕玻璃鏡片（crownglass）前表面為+4.50DS，在鏡片的後表面180度 軸線上測得最大值為-6.00D，在90度軸線上測得最小值為-3.00D，此鏡片處方該如何表示？', '["+1.50DS/+3.00DC×180", "+1.50DS/-3.00DC×090", "+1.50DS/-1.50DC×180", "+1.50DC×090/-1.50DC×180"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01250', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '染色鏡片會受鏡片的染料與鏡片屈光度影響，造成鏡片的穿透率而有所不同，當一患者配戴玻璃染色鏡片， 其右眼處方為OD：-2.50DC×180，左眼處方為OS：+1.00DS，其材料內有染料的玻璃鏡片穿透率會產生 何種改變？', '["右眼90度軸線附近顏色最深，左眼中央顏色最淺", "右眼180度軸線附近顏色最淺，左眼中央顏色最深", "右眼90度軸線附近顏色最淺，左眼中央顏色最淺", "右眼180度軸線附近顏色最深，左眼中央顏色最深"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01251', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '下列那一個鏡片材質在同一屈光設計所製作出的鏡片最輕？', '["冕玻璃", "CR-39樹脂（ColumbiaResin#39）", "聚碳酸酯（polycarbonate）", "鈦晶（Trivex）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01252', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '下列何種眼鏡架，不是以尼龍（nylon）為基礎或結合的？', '["醋酸纖維（celluloseacetate）", "聚醯胺（polyamide）", "碳纖維（carbonfiber）", "超彈性記憶樹脂（Grilamid）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01253', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '若有一鏡框的頂上部較緊貼於眉毛，或是鏡框框面的底端會觸及臉頰時，患者瞼睫毛會觸及鏡片部使得鏡 片會留下污漬，甚至影響患者的視線品質，下列何者無法改善此情況？', '["調窄鼻橋區域", "改變前傾角", "調寬鼻橋區域", "增加頂點距離"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
